func:
// Lưu giá trị
if (msg.topic === "nhakinh/nhietdo") flow.set('nhietdo', msg.payload);
if (msg.topic === "nhakinh/doam") flow.set('doam', msg.payload);
if (msg.topic === "nhakinh/doamdat") flow.set('doamdat', msg.payload);
if (msg.topic === "nhakinh/anhsang") flow.set('anhsang', msg.payload);
if (msg.topic === "nhakinh/khigas") flow.set('khigas', msg.payload);

// Dashboard outputs
var outputs = [null, null, null, null, null, msg]; // output 6 luôn có msg

if (msg.topic === "nhakinh/nhietdo") outputs[0] = msg;
if (msg.topic === "nhakinh/doam") outputs[1] = msg;
if (msg.topic === "nhakinh/doamdat") outputs[2] = msg;
if (msg.topic === "nhakinh/anhsang") outputs[3] = msg;
if (msg.topic === "nhakinh/khigas") outputs[4] = msg;

return outputs;

// 1. Kiểm tra kích hoạt cảnh báo
var alertEnabled = flow.get('alertEnabled');
if (alertEnabled === undefined) {
    alertEnabled = "1";
    flow.set('alertEnabled', "1");
}

if (alertEnabled !== "1" && alertEnabled !== true) {
    return null; 
}

// 2. Kiểm tra topic
var topic = msg.topic;
if (!topic) {
    node.warn("Lỗi dữ liệu: Không có msg.topic!");
    return null;
}

topic = topic.trim();

// 3. LẤY GIÁ TRỊ (HỖ TRỢ CẢ OBJECT + NUMBER)
var val;

if (typeof msg.payload === "object") {
    // Payload dạng JSON
    switch (topic) {
        case "nhakinh/nhietdo":
            val = msg.payload.temp;
            break;
        case "nhakinh/khigas":
            val = msg.payload.gas;
            break;
        case "nhakinh/doamdat":
            val = msg.payload.soil;
            break;
        case "nhakinh/anhsang":
            val = msg.payload.light;
            break;
        default:
            return null;
    }
} else {
    // Payload dạng số/string
    val = parseFloat(msg.payload);
}

// 4. Kiểm tra hợp lệ
if (val === undefined || isNaN(val)) {
    node.warn("Lỗi dữ liệu: Không tìm thấy giá trị hợp lệ! Payload: " + JSON.stringify(msg.payload));
    return null;
}

var chat_id = "6261296935";

// 5. Trạng thái cảnh báo
var wasAlerting = flow.get('isAlerting_' + topic) || false;
var isNowAlerting = false;
var alertMsg = "";
var safeMsg = "";

// 6. Logic cảnh báo
switch (topic) {
    case "nhakinh/nhietdo":
        if (val > 35) { 
            isNowAlerting = true; 
            alertMsg = "⚠️ **CẢNH BÁO:** Nhiệt độ quá CAO (`" + val + "°C`). Hãy bật Quạt/Bơm!"; 
        } else if (val < 18) { 
            isNowAlerting = true; 
            alertMsg = "❄️ **CẢNH BÁO:** Nhiệt độ quá THẤP (`" + val + "°C`). Hãy bật Sưởi!"; 
        }
        safeMsg = "✅ Nhiệt độ đã trở lại mức an toàn (`" + val + "°C`).";
        break;

    case "nhakinh/khigas":
        if (val > 2000) { 
            isNowAlerting = true; 
            alertMsg = "💨 **NGUY HIỂM:** Nồng độ Gas cao (`" + val + " PPM`). Hãy bật Quạt ngay!"; 
        }
        safeMsg = "✅ Nồng độ Gas đã giảm về mức an toàn (`" + val + " PPM`).";
        break;

    case "nhakinh/doamdat":
        if (val < 30) { 
            isNowAlerting = true; 
            alertMsg = "💧 **CẢNH BÁO:** Đất quá khô (`" + val + "%`). Hãy bật Bơm!"; 
        }
        safeMsg = "✅ Độ ẩm đất đã đủ (`" + val + "%`).";
        break;

    case "nhakinh/anhsang":
        if (val > 80) { 
            isNowAlerting = true; 
            alertMsg = "☀️ **CẢNH BÁO:** Nắng quá gắt (`" + val + "%`). Hãy kéo lưới che!"; 
        }
        safeMsg = "✅ Cường độ ánh sáng đã dịu lại (`" + val + "%`).";
        break;

    default:
        return null;
}

// 7. Gửi Telegram khi trạng thái thay đổi
if (isNowAlerting && !wasAlerting) {
    flow.set('isAlerting_' + topic, true);
    msg.payload = { 
        chatId: chat_id, 
        type: "message", 
        content: alertMsg,
        options: { parse_mode: "Markdown" } 
    };
    return msg;
} 
else if (!isNowAlerting && wasAlerting) {
    flow.set('isAlerting_' + topic, false);
    msg.payload = { 
        chatId: chat_id, 
        type: "message", 
        content: safeMsg,
        options: { parse_mode: "Markdown" } 
    };
    return msg;
}

return null;

var type = msg.payload.type;
var content = msg.payload.content;
var chatId = msg.payload.chatId;

// 1. KIỂM TRA VÀ BẬT CẢNH BÁO MẶC ĐỊNH
var ae = flow.get('alertEnabled');
if (ae === undefined) {
    flow.set('alertEnabled', "1");
    ae = "1";
}

// 6 ngõ ra: Quạt [0], Bơm [1], Sưởi [2], Lưới [3], Cảnh báo [4], Tele reply [5]
var out = [null, null, null, null, null, null]; 

// Lấy dữ liệu cảm biến từ flow (Phải đảm bảo đã lưu ở node Phân loại trước đó)
var nhietdo = flow.get('nhietdo') || "--";
var doam = flow.get('doam') || "--";
var doamdat = flow.get('doamdat') || "--";
var anhsang = flow.get('anhsang') || "--";
var khigas = flow.get('khigas') || "--";

// 2. XỬ LÝ LỖI HIỂN THỊ TRẠNG THÁI CẢNH BÁO
// Bao trọn các kiểu dữ liệu: số 1, chữ "1", boolean true, chữ "true"
var alertState = (ae === "1" || ae === 1 || ae === true || ae === "true") ? "🟢 ĐANG BẬT" : "🔴 ĐANG TẮT";

// Hàm điều khiển thiết bị và xuất thông báo phản hồi
function setControl(index, state, name) {
    out[index] = { payload: state };

    // Kiểm tra bao trọn các kiểu dữ liệu trạng thái để xuất thông báo chuẩn
    var isON = (state === "1" || state === 1 || state === true || state === "true");
    var statusMsg = isON ? "✅ Đã BẬT " + name : "🔴 Đã TẮT " + name;

    out[5] = { payload: { type: "message", chatId: chatId, content: statusMsg } };
}

// 3. DỰNG KHUNG VĂN BẢN HIỂN THỊ THÔNG SỐ CHUNG
var statusText = "🌿 **TRẠNG THÁI NHÀ KÍNH** 🌿\n";
statusText += "━━━━━━━━━━━━━\n";
statusText += "🌡 Nhiệt độ: `" + nhietdo + "°C`\n";
statusText += "💧 Độ ẩm khí: `" + doam + "%`\n";
statusText += "🌱 Độ ẩm đất: `" + doamdat + "%`\n";
statusText += "☀️ Ánh sáng: `" + anhsang + "%`\n";
statusText += "💨 Khí Gas: `" + khigas + " PPM`\n";
statusText += "🔔 Cảnh báo tự động: **" + alertState + "**\n";
statusText += "━━━━━━━━━━━━━\n";

// 4. XỬ LÝ LOGIC LỆNH (MENU, STATUS, HOẶC NÚT BẤM)
if (content === '/menu' || content === '/start') {
    // Lệnh Menu/Start -> Gửi thông số + Bảng điều khiển thiết bị
    var menuText = statusText + "👇 **BẢNG ĐIỀU KHIỂN**";
    out[5] = {
        payload: {
            type: "message",
            chatId: chatId,
            content: menuText,
            options: {
                parse_mode: "Markdown",
                reply_markup: JSON.stringify({
                    inline_keyboard: [
                        [{text: "🔄 Cập nhật thông số", callback_data: "status"}],
                        [{text: "🌬 Quạt: Bật", callback_data: "quat_1"}, {text: "🛑 Tắt", callback_data: "quat_0"}],
                        [{text: "💧 Bơm: Bật", callback_data: "bom_1"}, {text: "🛑 Tắt", callback_data: "bom_0"}],
                        [{text: "🔥 Sưởi: Bật", callback_data: "suoi_1"}, {text: "🛑 Tắt", callback_data: "suoi_0"}],
                        [{text: "🌤 Lưới: Kéo", callback_data: "luoi_1"}, {text: "🛑 Thu", callback_data: "luoi_0"}],
                        [{text: "🔔 BẬT Cảnh báo", callback_data: "alert_1"}, {text: "🔕 TẮT Cảnh báo", callback_data: "alert_0"}]
                    ]
                })
            }
        }
    };
} 
else if (content === '/status' || content === 'status') {
    // Lệnh Status -> Chỉ gửi thông số, có nút Cập nhật lại
    out[5] = {
        payload: {
            type: "message",
            chatId: chatId,
            content: statusText,
            options: {
                parse_mode: "Markdown",
                reply_markup: JSON.stringify({
                    inline_keyboard: [
                        [{text: "🔄 Cập nhật lại", callback_data: "status"}]
                    ]
                })
            }
        }
    };
} 
else {
    var cmd = content;

    // Xử lý các lệnh điều khiển từ nút bấm
    if (cmd === "/quat_on" || cmd === "quat_1") setControl(0, "1", "Quạt");
    else if (cmd === "/quat_off" || cmd === "quat_0") setControl(0, "0", "Quạt");

    else if (cmd === "/bom_on" || cmd === "bom_1") setControl(1, "1", "Bơm");
    else if (cmd === "/bom_off" || cmd === "bom_0") setControl(1, "0", "Bơm");

    else if (cmd === "/suoi_on" || cmd === "suoi_1") setControl(2, "1", "Sưởi");
    else if (cmd === "/suoi_off" || cmd === "suoi_0") setControl(2, "0", "Sưởi");

    else if (cmd === "/luoi_on" || cmd === "luoi_1") setControl(3, "1", "Lưới");
    else if (cmd === "/luoi_off" || cmd === "luoi_0") setControl(3, "0", "Lưới");

    // Cập nhật đồng bộ biến alertEnabled khi bấm Cảnh Báo
    else if (cmd === "/alert_on" || cmd === "alert_1") {
        flow.set('alertEnabled', "1");
        setControl(4, "1", "Hệ Thống Cảnh Báo");
    }
    else if (cmd === "/alert_off" || cmd === "alert_0") {
        flow.set('alertEnabled', "0");
        setControl(4, "0", "Hệ Thống Cảnh Báo");
    }
}

return out;

// Lưu vào global flow biến bật/tắt cảnh báo
flow.set('alertEnabled', msg.payload === "1" || msg.payload === true);
return null;

// 1. CHẶN THÔNG BÁO NẾU LỆNH ĐẾN TỪ TELEGRAM
// Chỉ thao tác trên Web UI mới có msg.socketid
if (!msg.socketid) {
    return null; 
}

// 2. PHẦN CODE XỬ LÝ THÔNG BÁO TỪ DASHBOARD VỀ TELEGRAM
var chat_id = "6261296935"; 

var deviceName = "";
var state = (msg.payload === "1" || msg.payload === true) ? "BẬT ✅" : "TẮT 🔴";

switch(msg.topic) {
    case "nhakinh/dieukhien/quat": 
        deviceName = "Quạt thông gió"; 
        break;
    case "nhakinh/dieukhien/bom": 
        deviceName = "Máy bơm nước"; 
        break;
    case "nhakinh/dieukhien/suoi": 
        deviceName = "Máy sưởi"; 
        break;
    case "nhakinh/dieukhien/luoi": 
        deviceName = "Lưới che nắng"; 
        break;
    case "nhakinh/dieukhien/canhbao": 
        deviceName = "Hệ thống cảnh báo tự động"; 
        break;
    default: 
        deviceName = "Thiết bị chưa xác định (" + msg.topic + ")";
}

var alertMsg = "📱 **[DASHBOARD]** " + deviceName + " vừa được **" + state + "**.";

msg.payload = {
    chatId: chat_id,
    type: "message",
    content: alertMsg,
    options: { parse_mode: "Markdown" } 
};

return msg;
